package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.fail;

import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private void invokeValidate(CSVFormat format) throws Exception {
        Method validateMethod = CSVFormat.class.getDeclaredMethod("validate");
        validateMethod.setAccessible(true);
        validateMethod.invoke(format);
    }

    @Test
    public void testValidate_quoteCharEqualsDelimiter_throws() {
        CSVFormat format = new CSVFormat(
                ',',
                Character.valueOf(','),
                Quote.MINIMAL,
                null,
                null,
                false,
                true,
                "\r\n",
                null,
                null,
                false);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> invokeValidate(format));
        if (!thrown.getMessage().contains("quoteChar character and the delimiter cannot be the same")) {
            fail("Unexpected exception message: " + thrown.getMessage());
        }
    }

    @Test
    public void testValidate_escapeEqualsDelimiter_throws() {
        CSVFormat format = new CSVFormat(
                ',',
                Character.valueOf('"'),
                Quote.MINIMAL,
                null,
                Character.valueOf(','),
                false,
                true,
                "\r\n",
                null,
                null,
                false);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> invokeValidate(format));
        if (!thrown.getMessage().contains("escape character and the delimiter cannot be the same")) {
            fail("Unexpected exception message: " + thrown.getMessage());
        }
    }

    @Test
    public void testValidate_commentStartEqualsDelimiter_throws() {
        CSVFormat format = new CSVFormat(
                ',',
                Character.valueOf('"'),
                Quote.MINIMAL,
                Character.valueOf(','),
                null,
                false,
                true,
                "\r\n",
                null,
                null,
                false);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> invokeValidate(format));
        if (!thrown.getMessage().contains("comment start character and the delimiter cannot be the same")) {
            fail("Unexpected exception message: " + thrown.getMessage());
        }
    }

    @Test
    public void testValidate_commentStartEqualsQuoteChar_throws() {
        Character sameChar = Character.valueOf('"');
        CSVFormat format = new CSVFormat(
                ',',
                sameChar,
                Quote.MINIMAL,
                sameChar,
                null,
                false,
                true,
                "\r\n",
                null,
                null,
                false);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> invokeValidate(format));
        if (!thrown.getMessage().contains("comment start character and the quoteChar cannot be the same")) {
            fail("Unexpected exception message: " + thrown.getMessage());
        }
    }

    @Test
    public void testValidate_commentStartEqualsEscape_throws() {
        Character sameChar = Character.valueOf('\\');
        CSVFormat format = new CSVFormat(
                ',',
                Character.valueOf('"'),
                Quote.MINIMAL,
                sameChar,
                sameChar,
                false,
                true,
                "\r\n",
                null,
                null,
                false);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> invokeValidate(format));
        if (!thrown.getMessage().contains("comment start and the escape character cannot be the same")) {
            fail("Unexpected exception message: " + thrown.getMessage());
        }
    }

    @Test
    public void testValidate_noEscapeAndQuoteNone_throws() {
        CSVFormat format = new CSVFormat(
                ',',
                null,
                Quote.NONE,
                null,
                null,
                false,
                true,
                "\r\n",
                null,
                null,
                false);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> invokeValidate(format));
        if (!thrown.getMessage().contains("No quotes mode set but no escape character is set")) {
            fail("Unexpected exception message: " + thrown.getMessage());
        }
    }

    @Test
    public void testValidate_headerDuplicates_throws() {
        CSVFormat format = new CSVFormat(
                ',',
                Character.valueOf('"'),
                Quote.MINIMAL,
                null,
                null,
                false,
                true,
                "\r\n",
                null,
                new String[]{"a", "b", "a"},
                false);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> invokeValidate(format));
        if (!thrown.getMessage().contains("The header contains duplicate names")) {
            fail("Unexpected exception message: " + thrown.getMessage());
        }
    }

    @Test
    public void testValidate_valid_noException() {
        CSVFormat format = new CSVFormat(
                ',',
                Character.valueOf('"'),
                Quote.MINIMAL,
                Character.valueOf('#'),
                Character.valueOf('\\'),
                false,
                true,
                "\r\n",
                null,
                new String[]{"a", "b", "c"},
                false);

        try {
            invokeValidate(format);
        } catch (Exception e) {
            fail("validate() should not throw, but threw: " + e.getCause());
        }
    }
}
